export default function App() {
  const [booting, setBooting] = useState(true);
  const [isAuthed, setIsAuthed] = useState(false);
  const [biometricsAvailable, setBiometricsAvailable] = useState(false);

  const refreshAuthState = useCallback(async () => {
    const authed = await getAuthenticated();
    setIsAuthed(authed);
  }, []);

  useEffect(() => {
    let mounted = true;

    (async () => {
      try {
        const authed = await getAuthenticated();
        const sensor = await rnBiometrics.isSensorAvailable().catch(() => ({ available: false }));
        if (!mounted) return;
        setIsAuthed(authed);
        setBiometricsAvailable(!!sensor?.available);
      } finally {
        if (mounted) setBooting(false);
      }
    })();

    return () => {
      mounted = false;
    };
  }, []);

  const handleLoginSuccess = useCallback(() => {
    setIsAuthed(true);
  }, []);

  const handleLogout = useCallback(async () => {
    await setAuthenticated(false);
    await refreshAuthState();
  }, [refreshAuthState]);

  if (booting) {
    return (
      <SafeAreaView style={styles.container}>
        <View style={styles.card}>
          <ActivityIndicator />
          <Text style={styles.note}>Loading…</Text>
        </View>
      </SafeAreaView>
    );
  }

  if (!isAuthed) {
    return (
      <LoginScreen biometricsAvailable={biometricsAvailable} onLoginSuccess={handleLoginSuccess} />
    );
  }

  return <HomeScreen onLogout={handleLogout} />;
}

